import{T as e}from"./chunks/theme.DUCXC5Zm.js";import{o as t,c as r,af as o,E as s}from"./chunks/framework.5D6DWnkB.js";const i="/images/nas-remote-guide.jpg",_=JSON.parse('{"title":"零基础搞定 NAS 外网访问！小白也能看硬盘里的电影","description":"","frontmatter":{"title":"零基础搞定 NAS 外网访问！小白也能看硬盘里的电影","date":"2026-03-30T00:00:00.000Z"},"headers":[],"relativePath":"tutorials/nas-remote.md","filePath":"tutorials/nas-remote.md"}'),n={name:"tutorials/nas-remote.md"},c=Object.assign(n,{setup(l){return(d,a)=>(t(),r("div",null,[a[0]||(a[0]=o('<h1 id="零基础搞定-nas-外网访问-小白也能看硬盘里的电影" tabindex="-1">零基础搞定 NAS 外网访问！小白也能看硬盘里的电影 <a class="header-anchor" href="#零基础搞定-nas-外网访问-小白也能看硬盘里的电影" aria-label="Permalink to &quot;零基础搞定 NAS 外网访问！小白也能看硬盘里的电影&quot;">​</a></h1><p><img src="'+i+'" alt="操作指引"></p><h2 id="为什么你的硬盘带不出门" tabindex="-1">为什么你的硬盘带不出门？ <a class="header-anchor" href="#为什么你的硬盘带不出门" aria-label="Permalink to &quot;为什么你的硬盘带不出门？&quot;">​</a></h2><p>很多人把旧电脑或者硬盘做成了 NAS（局域网存储），在家看电影、备份照片爽得很。但是一旦出了家门，手机流量就死活连不上家里的数据了，这就很让人抓狂。</p><p>其实，你不需要去折腾什么公网 IP，也不用去路由器里搞复杂的端口映射。今天我们就用最简单、最“傻瓜”的方式，一招打通外网访问！</p><h2 id="实操步骤-只需三步" tabindex="-1">实操步骤：只需三步！ <a class="header-anchor" href="#实操步骤-只需三步" aria-label="Permalink to &quot;实操步骤：只需三步！&quot;">​</a></h2><h3 id="_1-找到穿透神器入口" tabindex="-1">1. 找到穿透神器入口 <a class="header-anchor" href="#_1-找到穿透神器入口" aria-label="Permalink to &quot;1. 找到穿透神器入口&quot;">​</a></h3><p>在你的 CasaOS 主控台界面，目光往下看。 找到屏幕中间偏下，那个叫 <code>linkease</code>（易有云）的蓝色小云朵图标（如上图红框所示）。 不要犹豫，直接鼠标左键点进去！</p><h3 id="_2-登录你的专属账号" tabindex="-1">2. 登录你的专属账号 <a class="header-anchor" href="#_2-登录你的专属账号" aria-label="Permalink to &quot;2. 登录你的专属账号&quot;">​</a></h3><p>进入易有云的后台后，按照提示用微信扫码或者账号密码登录。 这相当于给你的 NAS 绑定了一把“远程大门”的钥匙。</p><h3 id="_3-见证奇迹的断网测试" tabindex="-1">3. 见证奇迹的断网测试 <a class="header-anchor" href="#_3-见证奇迹的断网测试" aria-label="Permalink to &quot;3. 见证奇迹的断网测试&quot;">​</a></h3><p>这是最爽的一步！ 拿起你的手机，<strong>关掉家里的 WiFi 连接</strong>，确保只使用 5G/4G 移动网络。然后打开手机上的“易有云”App。</p><p>🎉 <strong>结果：</strong> 你会发现，哪怕你不在家，家里的 2T 大硬盘也已经老老实实躺在你的手机里了！点开照片秒加载，看剧随便拖进度条。</p><p>这就是 P2P 直连打洞的魅力，完全不需要折腾复杂的网络配置，小白也能轻松拥有自己的私有云！</p>',14)),s(e)]))}});export{_ as __pageData,c as default};
